#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char a,b; scanf(" %c %c",&a,&b);
        int ra = (a=='R')?3:(a=='B'?2:1);
        int rb = (b=='R')?3:(b=='B'?2:1);
        char ans = (ra>=rb)?a:b;
        printf("%c\n",ans);
    }
    return 0;
}

